import { readFileSync, writeFileSync, existsSync, copyFileSync } from 'node:fs';

const indexPath = new URL('../openapi/index.ts', import.meta.url);
let content = readFileSync(indexPath, 'utf8');

const exportLine = "export { client } from './client.gen';";
const compatExportLine = "export type { QuerySerializerOptions, RequestResult } from './compat';";

// compat.gen.ts is checked into the repo and NOT regenerated by this script.
// We only ensure the index.ts re-exports it (since openapi-ts overwrites index.ts on each run).

if (!content.includes(compatExportLine)) {
  if (!content.endsWith('\n')) {
    content += '\n';
  }
  content += `${compatExportLine}\n`;
}

if (!content.includes(exportLine)) {
  if (!content.endsWith('\n')) {
    content += '\n';
  }
  content += `${exportLine}\n`;
}

writeFileSync(indexPath, content);
